import yaml
from pathlib import Path
import fcntl

ALLOWED_CONFIG_FILES = {'keywords.yaml', 'scoring_paper.yaml', 'scoring_tender.yaml'}

def validate_and_save_yaml(filename: str, content: str, config_dir: Path) -> dict:
    # 1. Check allowed file
    if filename not in ALLOWED_CONFIG_FILES:
        raise ValueError(f'Config file not allowed: {filename}')

    # 2. Validate YAML syntax
    try:
        data = yaml.safe_load(content)
    except yaml.YAMLError as e:
        raise ValueError(f'Invalid YAML: {str(e)}')

    # 3. Schema validation (example for keywords.yaml)
    if filename == 'keywords.yaml':
        if not isinstance(data, dict):
            raise ValueError('keywords.yaml must be a dict')
        if 'english' not in data and 'chinese' not in data:
            raise ValueError('keywords.yaml must have english or chinese keys')

    # 4. File lock and save
    filepath = config_dir / filename
    with open(filepath, 'w', encoding='utf-8') as f:
        fcntl.flock(f.fileno(), fcntl.LOCK_EX)  # Exclusive lock
        f.write(content)
        fcntl.flock(f.fileno(), fcntl.LOCK_UN)  # Unlock

    return {'status': 'success', 'file': filename}

