from fastapi.security import HTTPBasic, HTTPBasicCredentials
from fastapi import Depends, HTTPException
import secrets

security = HTTPBasic()

VALID_USERS = {
    'admin': 'hashed_password_here',
    'sales': 'hashed_password_here'
}

def authenticate(credentials: HTTPBasicCredentials = Depends(security)):
    correct_password = VALID_USERS.get(credentials.username)
    if not correct_password or not secrets.compare_digest(
        credentials.password.encode('utf-8'),
        correct_password.encode('utf-8')
    ):
        raise HTTPException(401, 'Invalid credentials', headers={'WWW-Authenticate': 'Basic'})
    return credentials.username

@app.get('/api/protected')
async def protected_route(username: str = Depends(authenticate)):
    return {'user': username}
